import logo from './logo.svg';
import './App.css';
import "@radix-ui/themes/styles.css";
import { Theme } from "@radix-ui/themes";
import MyApp from "./MyApp";

function App() {
  return (
    <Theme>
    <div className="App">

        <header className="App-header">
          <MyApp />
        </header>

    </div>
    </Theme>
  );
}

export default App;
